        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize default dictionary to store aggregated results
    aggregated_data = defaultdict(lambda: {"count": 0})

    # If no custom aggregation functions provided, use default statistics
    if aggregation_funcs is None:
        aggregation_funcs = {
            "count": lambda x: len(x),
            "avg_score": lambda x: sum(x) / len(x) if x else 0,
            "max_score": lambda x: max(x) if x else 0,
            "min_score": lambda x: min(x) if x else 0
        }

    # Iterate through each SearchResult in the input list
    for result in search_results:
        # Extract the metadata value for the group_by_field
        group_value = result.metadata.get(group_by_field)

        # If metadata value is missing, use 'unknown' as the group key
        if group_value is None:
            group_value = 'unknown'

        # For each group, accumulate statistics using either default calculations or custom functions
        group_data = aggregated_data[group_value]

        # Increment count for this group
        group_data["count"] += 1

        # Accumulate scores for average, max, and min calculations
        if "scores" not in group_data:
            group_data["scores"] = []
        group_data["scores"].append(result.score)

