                    if field_name not in group_data:
                        group_data[field_name] = []
                    group_data[field_name].append(field_value)

    # Convert defaultdict to regular dict and calculate final statistics
    final_result = {}
    for group_value, group_data in aggregated_data.items():
        # Calculate default statistics if scores exist
        if "scores" in group_data and group_data["scores"]:
            group_data["avg_score"] = aggregation_funcs["avg_score"](group_data["scores"])
            group_data["max_score"] = aggregation_funcs["max_score"](group_data["scores"])
            group_data["min_score"] = aggregation_funcs["min_score"](group_data["scores"])

        # Apply custom aggregation functions to non-default fields
