                        group_data[field_name] = func(group_data[field_name])
                    except Exception as e:
                        # Handle potential errors in custom functions
                        group_data[field_name] = None

        # Remove the temporary scores list
        if "scores" in group_data:
            del group_data["scores"]

        final_result[group_value] = group_data

    return final_result

